/// <summary>
/// Job to activate the configuration key for the new dimension in the ETGSPAIN model.
/// </summary>
class ETGSPAINActivateConfigurationKeyDim
{ 
}

Method.Source:
/// <summary>
/// Main method.
/// </summary>
/// <param name="_args">Arguments.</param>
public static void main(Args _args)
{

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        ConfigurationKeySet set = new ConfigurationKeySet();
        set.loadSystemSetup();
        set.enabled(configurationKeyNum(InventDimension1),  true);
        SysDictConfigurationKey::save(set.pack());
        SysSecurity::reload(true, true, true);
    }
}
